function generateReport($pdo, $filters) {
    $sql = "SELECT 
                r.id,
                r.title,
                r.description,
                r.amount,
                r.status,
                r.category,
                r.created_at,
                r.updated_at,
                u.username as created_by
            FROM reports r
            LEFT JOIN users u ON r.user_id = u.id
            WHERE 1=1";
    
    $params = [];
    
    // Date range filter
    if (!empty($filters['start_date'])) {
        $sql .= " AND r.created_at >= :start_date";
        $params[':start_date'] = $filters['start_date'] . ' 00:00:00';
    }
    
    if (!empty($filters['end_date'])) {
        $sql .= " AND r.created_at <= :end_date";
        $params[':end_date'] = $filters['end_date'] . ' 23:59:59';
    }
    
    // Status filter
    if (!empty($filters['status'])) {
        if (is_array($filters['status'])) {
            $placeholders = [];
            foreach ($filters['status'] as $idx => $status) {
                $key = ':status_' . $idx;
                $placeholders[] = $key;
                $params[$key] = $status;
            }
            $sql .= " AND r.status IN (" . implode(',', $placeholders) . ")";
        } else {
            $sql .= " AND r.status = :status";
            $params[':status'] = $filters['status'];
        }
    }
    
    // Category filter
    if (!empty($filters['category'])) {
        if (is_array($filters['category'])) {
            $placeholders = [];
            foreach ($filters['category'] as $idx => $category) {
                $key = ':category_' . $idx;
                $placeholders[] = $key;
                $params[$key] = $category;
            }
            $sql .= " AND r.category IN (" . implode(',', $placeholders) . ")";
        } else {
            $sql .= " AND r.category = :category";
            $params[':category'] = $filters['category'];
        }
    }
    
    // Amount range filter
    if (!empty($filters['min_amount'])) {
        $sql .= " AND r.amount >= :min_amount";
        $params[':min_amount'] = $filters['min_amount'];
    }
    
    if (!empty($filters['max_amount'])) {
        $sql .= " AND r.amount <= :max_amount";
        $params[':max_amount'] = $filters['max_amount'];
    }
    
    // Search filter
    if (!empty($filters['search'])) {
        $sql .= " AND (r.title LIKE :search OR r.description LIKE :search)";
        $params[':search'] = '%' . $filters['search'] . '%';
    }
    
    // User filter
    if (!empty($filters['user_id'])) {
        $sql .= " AND r.user_id = :user_id";
        $params[':user_id'] = $filters['user_id'];
    }
    
    // Sorting
    $allowedSortColumns = ['id', 'title', 'amount', 'status', 'category', 'created_at', 'updated_at'];
    $sortColumn = 'created_at';
    $sortOrder = 'DESC';
    
    if (!empty($filters['sort_by']) && in_array($filters['sort_by'], $allowedSortColumns)) {
        $sortColumn = $filters['sort_by'];
    }
    
    if (!empty($filters['sort_order']) && in_array(strtoupper($filters['sort_order']), ['ASC', 'DESC'])) {
        $sortOrder = strtoupper($filters['sort_order']);
    }
    
    $sql .= " ORDER BY r.{$sortColumn} {$sortOrder}";
    
    // Pagination
    $limit = !empty($filters['limit']) ? (int)$filters['limit'] : 50;
    $offset = !empty($filters['offset']) ? (int)$filters['offset'] : 0;
    
    $sql .= " LIMIT :limit OFFSET :offset";
    $params[':limit'] = $limit;
    $params[':offset'] = $offset;
    
    $stmt = $pdo->prepare($sql);
    
    foreach ($params as $key => $value) {
        if ($key === ':limit' || $key === ':offset') {
            $stmt->bindValue($key, $value, PDO::PARAM_INT);
        } else {
            $stmt->bindValue($key, $value);
        }
    }
    
    $stmt->execute();
    return $stmt->fetchAll(PDO::FETCH_ASSOC);
}

