function exportReportToCSV($pdo, $filters) {
    $filters['limit'] = 999999;
    $filters['offset'] = 0;
    
    $data = generateReport($pdo, $filters);
    
    header('Content-Type: text/csv');
    header('Content-Disposition: attachment; filename="report_' . date('Y-m-d_His') . '.csv"');
    
    $output = fopen('php://output', 'w');
    
    if (!empty($data)) {
        fputcsv($output, array_keys($data[0]));
        
        foreach ($data as $row) {
            fputcsv($output, $row);
        }
    }
    
    fclose($output);
    exit;
}

